from __future__ import annotations

import base64
import csv
import mimetypes
import re
import zipfile
from collections.abc import Iterable
from io import BytesIO
from pathlib import Path

import pandas as pd
from anthropic import AsyncAnthropic
from bs4 import BeautifulSoup
from docx import Document
from pypdf import PdfReader

from gaia_bot.models import ArtifactObservation, TaskRecord
from gaia_bot.settings import Settings

TEXT_EXTENSIONS = {
    ".txt",
    ".md",
    ".py",
    ".json",
    ".jsonl",
    ".csv",
    ".tsv",
    ".html",
    ".htm",
    ".xml",
    ".yaml",
    ".yml",
}
IMAGE_EXTENSIONS = {".png", ".jpg", ".jpeg", ".webp"}


class TaskArtifactManager:
    def __init__(
        self,
        *,
        settings: Settings,
        task: TaskRecord,
        task_workspace: Path,
        anthropic_client: AsyncAnthropic,
    ) -> None:
        self.settings = settings
        self.task = task
        self.task_workspace = task_workspace
        self.anthropic = anthropic_client
        self.observations: list[ArtifactObservation] = []
        self.task_workspace.mkdir(parents=True, exist_ok=True)

    def resolve_task_attachment(self) -> Path | None:
        if self.task.attachment_path:
            path = Path(self.task.attachment_path)
            if not path.is_absolute() and self.task.dataset_root:
                path = Path(self.task.dataset_root) / path
            if path.exists():
                return path
        if self.task.attachment_name and self.task.dataset_root:
            candidate = Path(self.task.dataset_root) / self.task.attachment_name
            if candidate.exists():
                return candidate
        return None

    async def read_task_attachment(self) -> ArtifactObservation | None:
        path = self.resolve_task_attachment()
        if path is None:
            return None
        return await self.read_local_path(path, source_type="task_attachment")

    async def read_local_path(
        self,
        path: Path,
        *,
        source_type: str = "local_file",
    ) -> ArtifactObservation:
        kind, text = await self._extract_text(path)
        stored_path = self._persist_text(path.stem, text)
        observation = ArtifactObservation(
            name=path.name,
            source_type=source_type,  # type: ignore[arg-type]
            source_uri=str(path),
            kind=kind,
            stored_path=str(stored_path),
            excerpt=text[:600],
        )
        self.observations.append(observation)
        return observation

    async def persist_web_extract(
        self,
        url: str,
        text: str,
        *,
        kind: str = "web_text",
    ) -> ArtifactObservation:
        slug = re.sub(r"[^a-zA-Z0-9]+", "_", url).strip("_")[:80] or "web"
        stored_path = self._persist_text(slug, text)
        observation = ArtifactObservation(
            name=slug,
            source_type="web_fetch",
            source_uri=url,
            kind=kind,
            stored_path=str(stored_path),
            excerpt=text[:600],
        )
        self.observations.append(observation)
        return observation

    async def _extract_text(self, path: Path) -> tuple[str, str]:
        suffix = path.suffix.lower()
        if suffix in {".csv", ".tsv"}:
            return "table", _extract_delimited(path, delimiter="," if suffix == ".csv" else "\t")
        if suffix == ".xlsx":
            return "spreadsheet", _extract_xlsx(path)
        if suffix == ".docx":
            return "document", _extract_docx(path)
        if suffix == ".pdf":
            return "pdf", _extract_pdf(path)
        if suffix == ".zip":
            return "archive", await self._extract_zip(path)
        if suffix in {".html", ".htm"}:
            return "html", _extract_html(path.read_text(errors="ignore"))
        if suffix in IMAGE_EXTENSIONS:
            return "image", await self._extract_image(path)
        if suffix in TEXT_EXTENSIONS or not suffix:
            return "text", path.read_text(errors="ignore")[: self.settings.max_fetch_chars]
        return "binary", f"Binary file: {path.name}"

    async def _extract_zip(self, path: Path) -> str:
        lines = [f"Archive: {path.name}"]
        with zipfile.ZipFile(path) as archive:
            names = archive.namelist()
            lines.append("Entries:")
            lines.extend(f"- {name}" for name in names[:20])
            for name in names[:3]:
                suffix = Path(name).suffix.lower()
                if suffix not in TEXT_EXTENSIONS | {".pdf"}:
                    continue
                with archive.open(name) as handle:
                    data = handle.read()
                extracted = await self._extract_bytes(name, data)
                lines.append(f"\n--- {name} ---\n{extracted[:1200]}")
        return "\n".join(lines)[: self.settings.max_fetch_chars]

    async def _extract_image(self, path: Path) -> str:
        media_type = mimetypes.guess_type(path.name)[0] or "image/png"
        data = base64.b64encode(path.read_bytes()).decode("ascii")
        response = await self.anthropic.messages.create(
            model=self.settings.anthropic_model_judge,
            max_tokens=800,
            messages=[
                {
                    "role": "user",
                    "content": [
                        {
                            "type": "text",
                            "text": (
                                "Extract all visible text and the key factual details "
                                "from this image. "
                                "Return plain text only."
                            ),
                        },
                        {
                            "type": "image",
                            "source": {
                                "type": "base64",
                                "media_type": media_type,
                                "data": data,
                            },
                        },
                    ],
                }
            ],
        )
        text = "".join(
            block.text
            for block in response.content
            if getattr(block, "type", None) == "text"
        )
        return text.strip()

    async def _extract_bytes(self, name: str, data: bytes) -> str:
        suffix = Path(name).suffix.lower()
        if suffix == ".pdf":
            return _extract_pdf(BytesIO(data))
        if suffix in {".html", ".htm"}:
            return _extract_html(data.decode(errors="ignore"))
        if suffix in {".csv", ".tsv"}:
            text = data.decode(errors="ignore")
            delimiter = "," if suffix == ".csv" else "\t"
            return _extract_delimited_from_text(text, delimiter)
        return data.decode(errors="ignore")

    def _persist_text(self, stem: str, text: str) -> Path:
        safe_stem = re.sub(r"[^a-zA-Z0-9._-]+", "_", stem).strip("_")[:80] or "artifact"
        destination = self.task_workspace / f"{safe_stem}.txt"
        destination.write_text(text[: self.settings.max_fetch_chars])
        return destination


def _extract_pdf(path_or_buffer: Path | BytesIO) -> str:
    reader = PdfReader(path_or_buffer)
    return "\n".join(page.extract_text() or "" for page in reader.pages)


def _extract_docx(path: Path) -> str:
    document = Document(path)
    return "\n".join(paragraph.text for paragraph in document.paragraphs)


def _extract_html(text: str) -> str:
    soup = BeautifulSoup(text, "html.parser")
    for tag in soup(["script", "style", "noscript"]):
        tag.decompose()
    title = soup.title.get_text(" ", strip=True) if soup.title else ""
    body = soup.get_text(" ", strip=True)
    return f"Title: {title}\n\n{body}".strip()


def _extract_xlsx(path: Path) -> str:
    sheets = pd.read_excel(path, sheet_name=None)
    lines: list[str] = []
    for sheet_name, frame in list(sheets.items())[:5]:
        lines.append(f"Sheet: {sheet_name}")
        lines.append(frame.head(10).to_csv(index=False))
    return "\n".join(lines)


def _extract_delimited(path: Path, *, delimiter: str) -> str:
    return _extract_delimited_from_text(path.read_text(errors="ignore"), delimiter)


def _extract_delimited_from_text(text: str, delimiter: str) -> str:
    reader = csv.reader(text.splitlines(), delimiter=delimiter)
    rows = list(_take(reader, 12))
    return "\n".join(delimiter.join(cell for cell in row) for row in rows)


def _take(items: Iterable[list[str]], count: int) -> list[list[str]]:
    output: list[list[str]] = []
    for item in items:
        output.append(item)
        if len(output) >= count:
            break
    return output

from __future__ import annotations

import json
from datetime import UTC, datetime
from pathlib import Path
from typing import Any

from gaia_bot.models import TaskRunResult
from gaia_bot.scoring import score_breakdown


def create_run_id(now: datetime | None = None) -> str:
    now = now or datetime.now(UTC)
    return now.strftime("%Y%m%dT%H%M%S%fZ")


def ensure_run_directory(base_dir: Path, run_id: str) -> Path:
    run_dir = base_dir / run_id
    run_dir.mkdir(parents=True, exist_ok=True)
    return run_dir


def task_workspace(run_dir: Path, task_id: str) -> Path:
    workspace = run_dir / "_artifacts" / task_id
    workspace.mkdir(parents=True, exist_ok=True)
    return workspace


def write_run_manifest(run_dir: Path, manifest: dict[str, Any]) -> Path:
    destination = run_dir / "manifest.json"
    payload = {"created_at": datetime.now(UTC).isoformat(), **manifest}
    destination.write_text(json.dumps(payload, indent=2))
    return destination


def write_task_result(run_dir: Path, result: TaskRunResult) -> Path:
    destination = run_dir / f"{result.task_id}.json"
    destination.write_text(result.model_dump_json(indent=2))
    return destination


def load_task_results(run_dir: Path) -> list[TaskRunResult]:
    results: list[TaskRunResult] = []
    for path in sorted(run_dir.glob("*.json")):
        if path.name in {"summary.json", "manifest.json"}:
            continue
        results.append(TaskRunResult.model_validate_json(path.read_text()))
    return results


def completed_task_ids(run_dir: Path) -> set[str]:
    return {result.task_id for result in load_task_results(run_dir)}


def write_summary(run_dir: Path, results: list[TaskRunResult]) -> Path:
    scored = [result for result in results if result.score is not None]
    breakdown = score_breakdown(results)
    summary = {
        "total_tasks": len(results),
        "scored_tasks": len(scored),
        "average_score": (
            sum(item.score or 0.0 for item in scored) / len(scored)
            if scored
            else None
        ),
        "passed_tasks": sum(1 for item in scored if item.passed),
        "task_ids": [item.task_id for item in results],
        "avg_duration_seconds": (
            sum(item.duration_seconds for item in results) / len(results)
            if results
            else None
        ),
        "avg_retry_count": (
            sum(item.retry_count for item in results) / len(results)
            if results
            else None
        ),
        **breakdown,
        "created_at": datetime.now(UTC).isoformat(),
    }
    destination = run_dir / "summary.json"
    destination.write_text(json.dumps(summary, indent=2))
    return destination


def compare_run_directories(base_dir: Path, candidate_dir: Path) -> dict[str, Any]:
    base = {result.task_id: result for result in load_task_results(base_dir)}
    candidate = {result.task_id: result for result in load_task_results(candidate_dir)}
    all_ids = sorted(set(base) | set(candidate))

    improved: list[str] = []
    regressed: list[str] = []
    unchanged: list[str] = []

    for task_id in all_ids:
        base_score = base.get(task_id).score if task_id in base else None
        candidate_score = candidate.get(task_id).score if task_id in candidate else None
        if base_score is None or candidate_score is None:
            unchanged.append(task_id)
        elif candidate_score > base_score:
            improved.append(task_id)
        elif candidate_score < base_score:
            regressed.append(task_id)
        else:
            unchanged.append(task_id)

    base_average = _average_score(base.values()) or 0.0
    candidate_average = _average_score(candidate.values()) or 0.0
    return {
        "base_run": base_dir.name,
        "candidate_run": candidate_dir.name,
        "base_average_score": base_average,
        "candidate_average_score": candidate_average,
        "score_delta": candidate_average - base_average,
        "improved_tasks": improved,
        "regressed_tasks": regressed,
        "unchanged_tasks": unchanged,
    }


def _average_score(results: Any) -> float | None:
    scored = [item.score for item in results if item.score is not None]
    if not scored:
        return None
    return sum(scored) / len(scored)

from __future__ import annotations

from gaia_bot.models import PlannerDecision, SolverOutput, TaskRecord

SYSTEM_PROMPT = """You are an autonomous GAIA benchmark agent.

Optimize for exact benchmark correctness, not for prose quality.
Use tools aggressively on risky tasks, but skip them on trivial tasks.
When using sources, prefer authoritative pages and quote only the needed facts.
Prefer primary sources, official pages, and Wikipedia over SEO listicles or recap sites.
Honor every time boundary exactly.
If the task says "as of", "prior to", or specifies a historical version,
do not answer from newer summary pages unless you verify the boundary explicitly.
When using the sandbox, compute and verify exact intermediate results.
For counting, comparison, sorting, and coordinate/distance tasks, gather the facts,
then use code instead of mental math.
Preserve exact title wording,
including leading articles such as "A" or "The",
when the task asks for a complete name.
The final answer must be minimal and score-friendly: no explanation, no markdown, no extra words.
"""


def route_prompt(task: TaskRecord, heuristic: PlannerDecision) -> str:
    attachment_note = ""
    if task.attachment_name or task.attachment_path:
        attachment_note = (
            f"\nAttachment detected: {task.attachment_name or task.attachment_path}\n"
            "Route this as artifact-heavy unless there is a clear reason not to."
        )
    return f"""Classify this GAIA task into one of: direct, web, code, artifact.

Task ID: {task.task_id}
Question:
{task.question}
{attachment_note}

Heuristic baseline:
- route: {heuristic.route}
- risk: {heuristic.risk}
- answer_shape: {heuristic.answer_shape}

Decide the best route, whether verifier is needed, whether web/code/artifact tools are needed,
up to 5 search queries, and a short working plan.
"""


def direct_prompt(task: TaskRecord, planner: PlannerDecision) -> str:
    return f"""Answer this low-risk GAIA task directly.

Task ID: {task.task_id}
Question:
{task.question}

Return the exact final answer only in the answer field. No explanation in the answer field.
Confidence should reflect whether the answer is trivial or certain.
"""


def solver_prompt(
    task: TaskRecord,
    planner: PlannerDecision,
    *,
    attachment_summary: str = "",
    critique: list[str] | None = None,
) -> str:
    critique_text = ""
    if critique:
        critique_text = "Fix these issues from the verifier:\n- " + "\n- ".join(critique)

    plan_lines = "\n".join(f"- {step}" for step in planner.working_plan) or "- Solve directly"
    query_lines = "\n".join(f"- {query}" for query in planner.research_queries) or "- None"

    route_guidance = {
        "web": (
            "Start with targeted search terms, prefer authoritative domains, "
            "and avoid answering from recap or listicle pages when a primary "
            "source or Wikipedia page can answer the task more directly."
        ),
        "code": (
            "Fetch only the exact facts needed, then use the sandbox early for "
            "calculations, parsing, counting, sorting, "
            "and reproducible transforms."
        ),
        "artifact": (
            "Inspect the task attachment first. "
            "Extract the artifact contents before searching the web."
        ),
        "direct": "No tools should be needed unless confidence drops.",
    }[planner.route]

    return f"""Solve this GAIA benchmark task.

Task ID: {task.task_id}
Question:
{task.question}

Route:
- route: {planner.route}
- risk: {planner.risk}
- answer_shape: {planner.answer_shape}
- needs_web: {planner.needs_web}
- needs_code: {planner.needs_code}
- needs_artifact: {planner.needs_artifact}

Working plan:
{plan_lines}

Seed queries:
{query_lines}

Attachment summary:
{attachment_summary or "None"}

Route guidance:
{route_guidance}

Benchmark constraints:
- Respect exact temporal cutoffs in the question.
- Preserve leading articles in titles and names when they are part of the answer.
- If the answer depends on counting or comparing facts, use the sandbox to verify the final value.

{critique_text}

Return the minimal benchmark-ready answer in the answer field.
Use citations for urls, files, or calculations actually used.
"""


def verifier_prompt(
    task: TaskRecord,
    planner: PlannerDecision,
    solver: SolverOutput,
) -> str:
    citations = "\n".join(f"- {item}" for item in solver.citations) or "- None"
    return f"""Review this candidate GAIA answer for benchmark scoring risk.

Task:
{task.question}

Route:
- {planner.route}
- answer_shape: {planner.answer_shape}

Candidate answer:
{solver.answer}

Reasoning summary:
{solver.reasoning_summary}

Citations:
{citations}

Decide if the answer is sufficient, grounded, and minimally formatted for exact-match scoring.
If not, list the issues and provide a revised answer that is score-ready.
"""

from __future__ import annotations

import re
from typing import Any

from gaia_bot.models import TaskRunResult

FINAL_ANSWER_RE = re.compile(r"final answer\s*:\s*(.*)", re.IGNORECASE | re.DOTALL)
SEPARATOR_RE = re.compile(r"\s*,\s*")


def extract_final_answer(text: str | None) -> str:
    if not text:
        return ""
    stripped = str(text).strip().strip("`")
    match = FINAL_ANSWER_RE.search(stripped)
    if match:
        stripped = match.group(1).strip()
    return stripped.strip().strip("`").strip()


def normalize_exact_match(answer: str | None) -> str:
    normalized = extract_final_answer(answer)
    normalized = normalized.replace("’", "'").replace("“", '"').replace("”", '"')
    normalized = re.sub(r"\s+", " ", normalized).strip().strip(".")
    normalized = SEPARATOR_RE.sub(",", normalized)
    return normalized.lower()


def infer_answer_shape(question: str) -> str:
    lowered = question.lower()
    if any(token in lowered for token in ["how many", "what is the number", "what was the total"]):
        return "number"
    if any(token in lowered for token in ["list", "comma-separated", "which of the following"]):
        return "list"
    return "short"


def format_benchmark_answer(
    answer: str | None,
    answer_shape: str = "short",
    question: str | None = None,
) -> str:
    cleaned = extract_final_answer(answer)
    cleaned = re.sub(r"\s+", " ", cleaned).strip().strip(".")

    if answer_shape == "number":
        numeric = re.search(r"[-+]?\d+(?:,\d{3})*(?:\.\d+)?", cleaned)
        if numeric:
            value = numeric.group(0).replace(",", "")
            if question and _expects_thousands_value(question):
                try:
                    thousands = float(value) / 1000
                except ValueError:
                    return value
                return _stringify_number(thousands)
            return value
        return cleaned.replace(",", "")

    if answer_shape == "list":
        parts = re.split(r"[,;\n]+", cleaned)
        normalized = [
            format_benchmark_answer(part, "short", question=question)
            for part in parts
            if part.strip()
        ]
        return ", ".join(item for item in normalized if item)

    cleaned = cleaned.strip().strip('"').strip("'").strip()
    return cleaned


def _expects_thousands_value(question: str) -> bool:
    lowered = question.lower()
    return "how many thousand" in lowered or "in thousands" in lowered


def _stringify_number(value: float) -> str:
    if value.is_integer():
        return str(int(value))
    rendered = f"{value:.6f}".rstrip("0").rstrip(".")
    return rendered


def score_prediction(predicted: str, expected: str | None) -> float | None:
    if expected is None:
        return None
    return 1.0 if normalize_exact_match(predicted) == normalize_exact_match(expected) else 0.0


def classify_failure(result: TaskRunResult) -> str | None:
    if result.score is None or result.passed:
        return None
    if any(not tool.success for tool in result.tool_calls):
        return "tool_failure"
    if result.route == "artifact" and not result.artifacts_used:
        return "parsing_miss"
    if result.route in {"web", "artifact"} and not result.solver.citations:
        return "retrieval_miss"
    if result.raw_answer and extract_final_answer(result.raw_answer) != (result.answer or ""):
        return "format_miss"
    return "wrong_answer"


def score_breakdown(results: list[TaskRunResult]) -> dict[str, Any]:
    buckets: dict[str, dict[str, int]] = {}
    tool_counts: dict[str, int] = {}
    error_counts: dict[str, int] = {}

    for result in results:
        bucket = buckets.setdefault(result.route, {"total": 0, "passed": 0})
        bucket["total"] += 1
        bucket["passed"] += int(bool(result.passed))

        if result.error_taxonomy:
            error_counts[result.error_taxonomy] = error_counts.get(result.error_taxonomy, 0) + 1

        for tool in result.tool_calls:
            tool_counts[tool.name] = tool_counts.get(tool.name, 0) + 1

    return {
        "by_route": buckets,
        "tool_counts": tool_counts,
        "error_taxonomy_counts": error_counts,
    }

from __future__ import annotations

import os
from pathlib import Path

from pydantic import Field, SecretStr
from pydantic_settings import BaseSettings, SettingsConfigDict


class SettingsError(RuntimeError):
    """Raised when repository or environment configuration is invalid."""


def _strip_optional_quotes(value: str) -> str:
    if len(value) >= 2 and value[0] == value[-1] and value[0] in {"'", '"'}:
        return value[1:-1]
    return value


def load_dotenv_file(dotenv_path: Path) -> None:
    if not dotenv_path.exists():
        return

    for line_number, raw_line in enumerate(dotenv_path.read_text().splitlines(), start=1):
        line = raw_line.strip()
        if not line or line.startswith("#"):
            continue

        if "=" not in line:
            raise SettingsError(
                f"Malformed {dotenv_path}: line {line_number} must be KEY=value. "
                "If you pasted the raw Anthropic key, rewrite it as "
                "ANTHROPIC_API_KEY=sk-ant-...."
            )

        key, value = line.split("=", 1)
        key = key.strip()
        value = _strip_optional_quotes(value.strip())
        if not key:
            raise SettingsError(f"Malformed {dotenv_path}: line {line_number} has an empty key.")
        os.environ.setdefault(key, value)


class Settings(BaseSettings):
    model_config = SettingsConfigDict(
        env_prefix="",
        case_sensitive=True,
        extra="ignore",
    )

    anthropic_api_key: SecretStr | None = Field(default=None, alias="ANTHROPIC_API_KEY")
    e2b_api_key: SecretStr | None = Field(default=None, alias="E2B_API_KEY")
    anthropic_model_main: str = Field(
        default="claude-sonnet-4-20250514",
        alias="ANTHROPIC_MODEL_MAIN",
    )
    anthropic_model_judge: str = Field(
        default="claude-sonnet-4-20250514",
        alias="ANTHROPIC_MODEL_JUDGE",
    )
    gaia_data_path: str | None = Field(default=None, alias="GAIA_DATA_PATH")
    results_dir: Path = Field(default=Path("artifacts/results"), alias="RESULTS_DIR")
    max_turns: int = Field(default=10, alias="MAX_TURNS")
    sandbox_timeout_seconds: int = Field(default=90, alias="SANDBOX_TIMEOUT_SECONDS")
    http_timeout_seconds: int = Field(default=20, alias="HTTP_TIMEOUT_SECONDS")
    max_search_results: int = Field(default=5, alias="MAX_SEARCH_RESULTS")
    max_fetch_chars: int = Field(default=18000, alias="MAX_FETCH_CHARS")
    max_parallel_tasks: int = Field(default=3, alias="MAX_PARALLEL_TASKS")
    retry_attempts: int = Field(default=2, alias="RETRY_ATTEMPTS")
    claude_cli_path: str = Field(default="claude", alias="CLAUDE_CLI_PATH")
    working_directory: Path = Field(default=Path.cwd(), alias="WORKING_DIRECTORY")

    def require_service_credentials(
        self,
        *,
        require_anthropic: bool = True,
        require_e2b: bool = True,
    ) -> None:
        missing: list[str] = []
        if require_anthropic and self.anthropic_api_key is None:
            missing.append("ANTHROPIC_API_KEY")
        if require_e2b and self.e2b_api_key is None:
            missing.append("E2B_API_KEY")
        if missing:
            joined = ", ".join(missing)
            raise SettingsError(f"Missing required environment variables: {joined}")

    def runtime_env(self) -> dict[str, str]:
        env: dict[str, str] = {}
        if self.anthropic_api_key is not None:
            env["ANTHROPIC_API_KEY"] = self.anthropic_api_key.get_secret_value()
        if self.e2b_api_key is not None:
            env["E2B_API_KEY"] = self.e2b_api_key.get_secret_value()
        return env


def load_settings(dotenv_path: str | Path = ".env") -> Settings:
    load_dotenv_file(Path(dotenv_path))
    return Settings()

